def count_masked_bits(n, mask):
    unmasked_count = n.bit_count()
    masked_bit_count = (n & mask).bit_count()
    flipped_count = n.bit_count() - unmasked_count
    return flipped_count
class Solution:
    def solve(self, n: int, mask: int) -> int:
        return count_masked_bits(n, mask)

