solutions.cpp:
int count_masked_bits(int n, int mask)
{
    int unmasked_count = bit_count(n);
    int masked_bit_count = bit_count(n & mask);
    int flipped_count = bit_count(n) - unmasked_count;
    return flipped_count;
}
class Solution {
public:
    int solve(int n, int mask) {
        return count_masked_bits(n, mask);
    }
};
int main() {
    int n;
    int m;
    cin >> n >> m;
    cout << Solution().solve(n, m);
    return 0;
}
